SELECT 


, A.RNUM
FROM (
	SELECT 


	, ROWNUM RNUM FROM (
		SELECT



		FROM MST.TB_IP_HOST_MST A




			AND A.SRSSOFFICESCODE IN ( SELECT SLOFFICECODE FROM MST.TB_LVL_SUB_CD WHERE SLVL_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
			AND NLVL_MST_SEQ IN

				#{item.nlvlSeq}

			))



	) A WHERE ROWNUM <= #{lastIndex}
) A WHERE A.RNUM >= #{firstIndex}

SELECT count(1) totalCount FROM MST.TB_IP_HOST_MST A
AND A.SRSSOFFICESCODE IN ( SELECT SLOFFICECODE FROM MST.TB_LVL_SUB_CD WHERE SLVL_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
))

SELECT 


, A.RNUM
FROM (
	SELECT 


	, ROWNUM RNUM FROM (
		SELECT


		FROM	(
					SELECT	
						,	DECODE(B.PIP_PREFIX,NULL,'CT0001' ,'CT0004') AS SIP_CREATE_TYPE_CD
					FROM	(
								SELECT	
								FROM	MST.TB_IP_HOST_MST	A

							)	A 
					LEFT OUTER JOIN   MST.TB_IP_RESERVED B  ON B.PIP_PREFIX >>= PIP_HOST_INET
				)	A

		WHERE 1=1


			AND A.SRSSOFFICESCODE IN ( SELECT SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB WHERE SSVC_OBJ_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
			AND NLVL_MST_SEQ IN

				#{item.nlvlSeq}

			))


		AND A.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}



	) A WHERE ROWNUM <= #{lastIndex}
) A WHERE A.RNUM >= #{firstIndex}

SELECT count(1) totalCount FROM ( SELECT , DECODE(B.PIP_PREFIX,NULL,'CT0001' ,'CT0004') AS SIP_CREATE_TYPE_CD FROM ( SELECT FROM MST.TB_IP_HOST_MST A
) A LEFT OUTER JOIN MST.TB_IP_RESERVED B ON B.PIP_PREFIX >>= PIP_HOST_INET ) A
WHERE 1=1
AND A.SRSSOFFICESCODE IN ( SELECT SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB WHERE SSVC_OBJ_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
))
AND A.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}

SELECT A.SRSSOFFICESCODE AS SRSSOFFICESCODE , B.SLVL_NM as SRSSOFFICESNM FROM MST.TB_IP_HOST_MST A , MST.TB_LVL_CD B WHERE 1=1 AND A.SRSSOFFICESCODE = B.SLVL_CD(+)
AND A.SIP_HOST_TYPE_CD = #{sipHostTypeCd, jdbcType=CHAR}
AND A.SRSSOFFICESCODE IN ( SELECT SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB WHERE SSVC_OBJ_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
))
GROUP BY A.SRSSOFFICESCODE, B.SLVL_NM ORDER BY B.SLVL_NM

SELECT A.SRSSOFFICESCODE AS code , B.SLVL_NM as name FROM MST.TB_IP_HOST_MST A , MST.TB_LVL_CD B WHERE 1=1
AND A.SRSSOFFICESCODE = B.SLVL_CD(+)
AND A.SIP_HOST_TYPE_CD = #{sipHostTypeCd, jdbcType=CHAR}
AND A.SRSSOFFICESCODE IN ( SELECT SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB WHERE SSVC_OBJ_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
))
GROUP BY A.SRSSOFFICESCODE, B.SLVL_NM ORDER BY B.SLVL_NM
